mapper.delete:

DELETE r1 FROM conversation_memory_ref r1
JOIN (
    SELECT id FROM (

        SELECT id, ROW_NUMBER() OVER (PARTITION BY appId ORDER BY createdAt DESC, id DESC) rn
        FROM conversation_memory_ref
    ) t
    WHERE t.rn > #{keepCount}
) old ON old.id = r1.id

DELETE FROM conversation_memory_ref
WHERE id IN (
    SELECT id FROM (

        SELECT id, contentBytes,
               SUM(contentBytes) OVER (ORDER BY createdAt ASC, id ASC) AS rollingBytes
        FROM conversation_memory_ref
        WHERE appId = #{appId}
    ) t
    WHERE t.rollingBytes <= #{overflow}
)
